        'downloaded_files': downloaded
    }

import pandas as pd

def main(cleaned_files, geo_data):
    anomalies = []
    for file_info in cleaned_files:
        df = file_info['dataframe']
        # 检测异常访问频率
        if 'timestamp' in df.columns and 'ip' in df.columns:
            ip_counts = df['ip'].value_counts()
            suspicious_ips = ip_counts[ip_counts > 100].index.tolist()
            for ip in suspicious_ips:
                anomalies.append({
                    'type': 'high_frequency',
                    'ip': ip,
                    'count': int(ip_counts[ip]),
                    'filename': file_info['filename']
                })
        # 检测可疑用户代理
        if 'user_agent' in df.columns:
            suspicious_agents = df[df['user_agent'].str.contains('bot|crawler|spider', case=False, na=False)]
            for _, row in suspicious_agents.iterrows():
                anomalies.append({
                    'type': 'suspicious_agent',
                    'ip': row.get('ip', 'unknown'),
                    'user_agent': row['user_agent'],
                    'filename': file_info['filename']
                })
    return {
        'status': 'success',
        'anomalies': anomalies,
        'total_anomalies': len(anomalies)
    }

